const input = $input.first().json;
const calId = Object.keys(input.calendars)[0];
const busyPeriods = input.calendars[calId].busy || [];

const now = new Date();
const dates = {};

function toAmsterdamDate(date) {
  return date.toLocaleDateString('en-CA', { timeZone: 'Europe/Amsterdam' });
}

function getAmsterdamOffsetMs(date) {
  const parse = s => new Date(s.replace(',', '') + ':00Z').getTime();
  const amStr = date.toLocaleString('en-CA', { timeZone: 'Europe/Amsterdam', hour12: false, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  const utcStr = date.toLocaleString('en-CA', { timeZone: 'UTC', hour12: false, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  return parse(amStr) - parse(utcStr);
}

function overlapsBusy(slotStart, busy) {
  const slotEnd = new Date(slotStart.getTime() + 30 * 60 * 1000);
  return busy.some(p => p.start && p.end && slotStart < new Date(p.end) && slotEnd > new Date(p.start));
}

const nowHour = parseInt(now.toLocaleString('nl-NL', { timeZone: 'Europe/Amsterdam', hour: 'numeric', hour12: false }));
const todayStr = toAmsterdamDate(now);

for (let i = 0; i < 14; i++) {
  const d = new Date(now);
  d.setDate(d.getDate() + i);
  const dateStr = toAmsterdamDate(d);
  if (dateStr === todayStr && nowHour >= 16) continue;
  const dow = new Date(dateStr + 'T12:00:00Z').getDay();
  if (dow === 0 || dow === 6) continue;

  const [year, month, day] = dateStr.split('-').map(Number);
  const available = [];

  for (let hour = 9; hour < 18; hour++) {
    for (const minute of [0, 30]) {
      if (hour === 17 && minute === 30) break;
      const pad = n => String(n).padStart(2, '0');
      const utcDate = new Date(`${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00Z`);
      const slotUtc = new Date(utcDate.getTime() - getAmsterdamOffsetMs(utcDate));
      if (slotUtc <= now) continue;
      if (!overlapsBusy(slotUtc, busyPeriods)) {
        available.push(slotUtc.toLocaleString('nl-NL', { timeZone: 'Europe/Amsterdam', hour: '2-digit', minute: '2-digit', hour12: false }));
      }
    }
  }

  if (available.length > 0) dates[dateStr] = available;
}

return [{ json: { dates } }];
